import { Client, Account, Databases } from "appwrite";

const client = new Client()
    .setEndpoint("https://sgp.cloud.appwrite.io/v1")
    .setProject("69b2a05d000ff1fe0013");

const account = new Account(client);
const databases = new Databases(client);

// Ping the Appwrite backend server to verify the setup
client.ping()
    .then(() => {
        console.log('✅ AppWrite connection successful!');
        console.log('Project ID:', '69b2a05d000ff1fe0013');
        console.log('Project Name:', 'facebook');
        console.log('Endpoint:', 'https://sgp.cloud.appwrite.io/v1');
    })
    .catch((error) => {
        console.error('❌ AppWrite connection failed:', error);
        console.log('Using fallback localStorage database for demonstration.');
    });

export { client, account, databases };
